  // =========================================================================
  // unused_funarg_1
  // =========================================================================
  test("unused_funarg_1") {
    assertCompresses(
      input = """function f(a, b, c, d, e) {
            return a + b;
        }""".stripMargin.trim,
      expected = """function f(a, b) {
            return a + b;
        }""".stripMargin.trim,
      options = AllOff.copy(
        keepFargs = false,
        unused = true
      )
    )
  }

